  const serviceBadge=serviceTypeConfig[booking_details?.service_type]||'bg-gray-100 text-gray-700'
  const mapsUrl=`https://maps.google.com/?q=${encodeURIComponent([location_info?.address||'',location_info?.unit_number||'',location_info?.city||'',location_info?.state||'',location_info?.zip_code||''].filter(Boolean).join(' '))}`
  const asgnStatus=assignment?.status
  const showStartJob=asgnStatus==='accepted'
  const showCompleteJob=asgnStatus==='in_progress'
  return`<div id="booking-detail" class="absolute inset-0 z-[2000] bg-gray-100 flex flex-col animate-slide-up"><header class="bg-white border-b border-gray-100 text-gray-800 px-4 pt-3 pb-3 shrink-0"><div class="flex items-center gap-3"><button id="close-detail" class="w-8 h-8 bg-gray-100 rounded-lg flex items-center justify-center active:scale-90 transition-transform"><svg class="w-5 h-5 text-gray-500" viewBox="0 0 24 24">${iconsSvg.chevronLeft}</svg></button><div><h1 class="text-xs font-semibold leading-tight">${location_info?.city||''}, ${location_info?.state||''} &mdash; ${booking_details?.service_type||''}</h1></div></div></header>${showCompleteJob?`<div class="bg-red-600 px-4 py-4 flex items-center gap-3 shrink-0"><span class="relative flex h-3 w-3"><span class="animate-ping absolute inline-flex h-full w-full rounded-full bg-white opacity-75"></span><span class="relative inline-flex rounded-full h-3 w-3 bg-white"></span></span><span class="text-base font-bold text-white">Job In Progress</span></div>`:''}<main class="flex-1 overflow-y-auto pb-0">${booking_details?.photo_url?`<div class="h-48 bg-gray-200"><img src="${booking_details.photo_url}" class="w-full h-full object-cover" alt="" /></div>`:''}<div class="p-4 space-y-4 ${showCompleteJob?'pb-32':'pb-24'}"><div class="flex items-center justify-between bg-white rounded-xl p-4 shadow-sm border border-gray-100"><div class="flex items-center gap-3"><span class="text-xs px-2.5 py-1 rounded-full font-semibold ${sc.bg} ${sc.text} capitalize">${(status||'pending').replace('_',' ')}</span><span class="text-xs px-2.5 py-1 rounded-full font-medium ${serviceBadge}">${booking_details?.service_type||'Service'}</span></div><span class="text-xl font-bold text-gray-900">$${booking_details?.price||0}</span></div><div class="bg-white rounded-xl p-4 shadow-sm border border-gray-100"><h3 class="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-3">Customer</h3><p class="text-base font-semibold text-gray-800">${customer_info?.name||'Unknown'}</p>${customer_info?.email?`<a href="mailto:${customer_info.email}" class="flex items-center gap-2 text-sm text-gray-500 mt-2"><svg class="w-4 h-4" viewBox="0 0 24 24">${iconsSvg.mail}</svg><span>${customer_info.email}</span></a>`:''}${customer_info?.phone?`<a href="tel:${customer_info.phone.replace(/[^0-9+]/g,'')}" class="flex items-center gap-2 text-sm text-gray-500 mt-1.5"><svg class="w-4 h-4" viewBox="0 0 24 24">${iconsSvg.phone}</svg><span>${customer_info.phone}</span></a>`:''}</div><div class="bg-white rounded-xl p-4 shadow-sm border border-gray-100"><h3 class="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-3">Location</h3><a href="${mapsUrl}" target="_blank" rel="noopener" class="block text-sm text-brand hover:text-brand-700 active:text-brand-700 transition"><p>${location_info?.address||''}${location_info?.unit_number?' '+location_info.unit_number:''}</p><p>${location_info?.city||''},${location_info?.state||''} ${location_info?.zip_code||''}</p></a></div>${booking_details?.preferred_date||booking_details?.preferred_time?`<div class="bg-white rounded-xl p-4 shadow-sm border border-gray-100"><h3 class="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-3">Schedule</h3>${booking_details?.preferred_date?`<div class="flex items-center gap-2 text-sm text-gray-700"><svg class="w-4 h-4 text-gray-400" viewBox="0 0 24 24">${iconsSvg.calendar}</svg><span>${formatDate(booking_details.preferred_date)}</span></div>`:''}${booking_details?.preferred_time?`<div class="flex items-center gap-2 text-sm text-gray-700 mt-2"><svg class="w-4 h-4 text-gray-400" viewBox="0 0 24 24">${iconsSvg.clock}</svg><span>${booking_details.preferred_time}</span></div>`:''}</div>`:''}${booking_details?.estimated_items&&booking_details.estimated_items.length?`<div class="bg-white rounded-xl p-4 shadow-sm border border-gray-100"><h3 class="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-3">Items</h3>${booking_details.estimated_items.map(i=>`<div class="flex items-center gap-2 text-sm text-gray-700"><svg class="w-4 h-4 text-gray-400 shrink-0" viewBox="0 0 24 24">${iconsSvg.package}</svg><span>${i}</span></div>`).join('')}${booking_details?.estimated_volume?`<p class="text-xs text-gray-400 mt-2">${booking_details.estimated_volume}</p>`:''}</div>`:''}<div class="bg-white rounded-xl p-4 shadow-sm border border-gray-100"><h3 class="text-xs font-semibold text-gray-400 uppercase tracking-wider mb-3">Details</h3><p class="text-sm text-gray-700 whitespace-pre-wrap">${booking_details?.details||'No additional details'}</p></div><p class="text-xs text-gray-400 text-center">Created ${formatDateTime(created_at)}</p></div></main>${showStartJob||showCompleteJob?`<div class="bg-white border-t border-gray-200 px-4 py-3 shrink-0 shadow-[0_-4px_12px_rgba(0,0,0,0.05)]">${showStartJob?`<button id="start-job-btn" class="w-full bg-brand text-white font-semibold py-3 rounded-xl hover:bg-secondary active:scale-[0.98] transition text-sm">Start Job</button>`:''}${showCompleteJob?`<button id="complete-job-btn" class="w-full bg-brand text-white font-semibold py-3 rounded-xl hover:bg-secondary active:scale-[0.98] transition text-sm">Mark Job Complete</button>`:''}</div>`:''}</div>`
